{"path":"cortex_m0_core/rtl/cortex_m0_core.sv","content":"//=============================================================================
// Module: cortex_m0_core
// Description: 32-bit ARMv6-M processor core (Cortex-M0 subset)
//              3-stage pipeline: FETCH -> DECODE -> EXECUTE
//              Flat monolithic design - no sub-modules
// Reference:   cortex_m0_core/mas/cortex_m0_core_spec.md
//=============================================================================

module cortex_m0_core #(
    parameter integer          IRQ_NUM  = 32,
    parameter logic [31:0]     INIT_PC  = 32'h0000_0004,
    parameter logic [31:0]     INIT_SP  = 32'h0000_0000
) (
    // ------------------------------------------------------------------
    // Clock & Reset
    // ------------------------------------------------------------------
    input  logic        HCLK,
    input  logic        HRESETn,

    // ------------------------------------------------------------------
    // AHB-Lite Master Interface
    // ------------------------------------------------------------------
    output logic [31:0] HADDR,
    output logic [2:0]  HBURST,
    output logic        HMASTLOCK,
    output logic [3:0]  HPROT,
    output logic [2:0]  HSIZE,
    output logic [1:0]  HTRANS,
    output logic [31:0] HWDATA,
    output logic        HWRITE,
    input  logic [31:0] HRDATA,
    input  logic        HREADY,
    input  logic        HRESP,

    // ------------------------------------------------------------------
    // Interrupts (NVIC)
    // ------------------------------------------------------------------
    input  logic [IRQ_NUM-1:0] IRQ,
    input  logic        NMI,
    output logic        EVTEXEC,

    // ------------------------------------------------------------------
    // Debug
    // ------------------------------------------------------------------
    output logic        HALTED,
    input  logic        DBGRQ,
    output logic        DBGACK
);

    // ==================================================================
    // 1. Local Parameters — FSM State Encoding
    // ==================================================================
    localparam logic [3:0] ST_RESET       = 4'd0;
    localparam logic [3:0] ST_FETCH       = 4'd1;
    localparam logic [3:0] ST_DECODE      = 4'd2;
    localparam logic [3:0] ST_EXECUTE     = 4'd3;
    localparam logic [3:0] ST_MEM_WAIT    = 4'd4;
    localparam logic [3:0] ST_STALL       = 4'd5;
    localparam logic [3:0] ST_SLEEP       = 4'd6;
    localparam logic [3:0] ST_DBG_HALT    = 4'd7;
    localparam logic [3:0] ST_EXC_ENTRY   = 4'd8;
    localparam logic [3:0] ST_EXC_STACK   = 4'd9;
    localparam logic [3:0] ST_EXC_VFETCH  = 4'd10;
    localparam logic [3:0] ST_EXC_RETURN  = 4'd11;
    localparam logic [3:0] ST_EXC_UNSTACK = 4'd12;

    // ==================================================================
    // 2. Local Parameters — ALU Operation Encoding
    // ==================================================================
    localparam logic [4:0] ALU_ADD  = 5'd0;
    localparam logic [4:0] ALU_ADC  = 5'd1;
    localparam logic [4:0] ALU_SUB  = 5'd2;
    localparam logic [4:0] ALU_SBC  = 5'd3;
    localparam logic [4:0] ALU_RSB  = 5'd4;
    localparam logic [4:0] ALU_AND  = 5'd5;
    localparam logic [4:0] ALU_ORR  = 5'd6;
    localparam logic [4:0] ALU_EOR  = 5'd7;
    localparam logic [4:0] ALU_BIC  = 5'd8;
    localparam logic [4:0] ALU_LSL  = 5'd9;
    localparam logic [4:0] ALU_LSR  = 5'd10;
    localparam logic [4:0] ALU_ASR  = 5'd11;
    localparam logic [4:0] ALU_MUL  = 5'd12;
    localparam logic [4:0] ALU_MOV  = 5'd13;
    localparam logic [4:0] ALU_MVN  = 5'd14;
    localparam logic [4:0] ALU_NOP  = 5'd15;
    localparam logic [4:0] ALU_CMP  = 5'd16;
    localparam logic [4:0] ALU_CMN  = 5'd17;
    localparam logic [4:0] ALU_TST  = 5'd18;

    // ==================================================================
    // 3. Local Parameters — Instruction Class Encoding
    // ==================================================================
    localparam logic [3:0] CLS_ALU    = 4'd0;
    localparam logic [3:0] CLS_SHIFT  = 4'd1;
    localparam logic [3:0] CLS_CMP    = 4'd2;
    localparam logic [3:0] CLS_MOVE   = 4'd3;
    localparam logic [3:0] CLS_MUL    = 4'd4;
    localparam logic [3:0] CLS_LOAD   = 4'd5;
    localparam logic [3:0] CLS_STORE  = 4'd6;
    localparam logic [3:0] CLS_LOADM  = 4'd7;
    localparam logic [3:0] CLS_STOREM = 4'd8;
    localparam logic [3:0] CLS_BRANCH = 4'd9;
    localparam logic [3:0] CLS_BL     = 4'd10;
    localparam logic [3:0] CLS_BX     = 4'd11;
    localparam logic [3:0] CLS_SYSTEM = 4'd12;

    // ==================================================================
    // 4. Local Parameters — Exception Numbers
    // ==================================================================
    localparam logic [8:0] EXC_RESET     = 9'd1;
    localparam logic [8:0] EXC_NMI       = 9'd2;
    localparam logic [8:0] EXC_HARDFAULT = 9'd3;
    localparam logic [8:0] EXC_SVCALL    = 9'd11;
    localparam logic [8:0] EXC_PENDSV    = 9'd14;
    localparam logic [8:0] EXC_SYSTICK   = 9'd15;
    // IRQ[n] = 16 + n

    // ==================================================================
    // 5. Internal Signal Declarations
    // ==================================================================

    // --- Reset synchronizer ---
    logic        rst_sync_n;

    // --- Input synchronizers ---
    logic [IRQ_NUM-1:0] irq_sync1, irq_sync2;
    logic        nmi_sync1, nmi_sync2, nmi_delayed, nmi_edge;
    logic        dbgrq_sync1, dbgrq_sync2;

    // --- Pipeline FSM ---
    logic [3:0]  fsm_state;
    logic [3:0]  stall_return_state;

    // --- Program Counter ---
    logic [31:0] pc_reg;
    logic [31:0] pc_next;
    logic        pc_write_en;

    // --- Instruction Register ---
    logic [31:0] instr_reg;       // Full instruction (32-bit, or zero-extended 16-bit)
    logic [15:0] instr_hw;        // The active halfword being decoded
    logic        instr_is_32bit;  // Detected 32-bit instruction

    // --- General-Purpose Register File ---
    logic [31:0] gprf        [0:12]; // R0-R12
    logic [31:0] msp_reg;             // Main Stack Pointer
    logic [31:0] psp_reg;             // Process Stack Pointer
    logic [31:0] lr_reg;              // Link Register (R14)

    // Register read ports
    logic [3:0]  reg_r1_sel;
    logic [31:0] reg_r1_data;
    logic [3:0]  reg_r2_sel;
    logic [31:0] reg_r2_data;

    // Register write port
    logic [3:0]  reg_w_sel;
    logic [31:0] reg_w_data;
    logic        reg_w_en;

    // SP banking control
    logic        handler_mode;
    logic        control_spsel;
    logic [31:0] active_sp;      // Currently active stack pointer

    // --- Special Registers ---
    logic        apsr_n, apsr_z, apsr_c, apsr_v;
    logic [31:0] apsr_reg;
    logic [31:0] ipsr_reg;
    logic [31:0] epsr_reg;       // T-bit at [24], always 1
    logic        primask_pm;     // PRIMASK[0]
    logic        control_spsel_reg; // CONTROL[0]

    // --- Decoder outputs ---
    logic [3:0]  dec_class;
    logic [4:0]  dec_alu_op;
    logic [3:0]  dec_rd;
    logic [3:0]  dec_rn;
    logic [3:0]  dec_rm;
    logic [31:0] dec_imm;
    logic [4:0]  dec_shift_amt;
    logic [1:0]  dec_mem_size;
    logic        dec_mem_signext;
    logic        dec_write_en;
    logic        dec_flag_en;
    logic        dec_branch_en;
    logic [3:0]  dec_branch_cond;
    logic        dec_is_32bit;
    logic [7:0]  dec_reg_list;   // For PUSH/POP/LDM/STM
    logic        dec_push_lr;    // PUSH includes LR
    logic        dec_pop_pc;     // POP includes PC

    // --- ALU ---
    logic [31:0] alu_operand_a;
    logic [31:0] alu_operand_b;
    logic [31:0] alu_result;
    logic        alu_flag_n, alu_flag_z, alu_flag_c, alu_flag_v;

    // --- Barrel Shifter ---
    logic [31:0] shift_result;
    logic        shift_carry;

    // --- Condition code evaluator ---
    logic        cond_eval_result;

    // --- AHB-Lite interface registers ---
    logic [31:0] ahb_haddr_next;
    logic [2:0]  ahb_hsize_next;
    logic [1:0]  ahb_htrans_next;
    logic        ahb_hwrite_next;
    logic [3:0]  ahb_hprot_next;
    logic [31:0] ahb_hwdata_next;
    logic [31:0] hrdata_capture; // Captured read data

    // --- NVIC ---
    logic [IRQ_NUM-1:0] nvic_pending;
    logic [IRQ_NUM-1:0] nvic_enable;
    logic [IRQ_NUM-1:0] nvic_active;
    logic [1:0]         nvic_priority [0:IRQ_NUM-1];

    // NVIC arbitration outputs
    logic               nvic_irq_valid;      // Any pending+enabled IRQ
    logic [$clog2(IRQ_NUM+1)-1:0] nvic_highest_idx; // Index of highest priority pending+enabled
    logic [1:0]         nvic_highest_pri;     // Priority of highest

    // Exception detection
    logic        exception_pending;
    logic [8:0]  exc_num;
    logic [1:0]  exc_priority;
    logic        exc_taken;

    // HardFault cause
    logic [1:0]  hf_cause; // 00=undef, 01=bus, 10=stacking, 11=other

    // --- Exception stacking ---
    logic [2:0]  stack_count;       // 0-7 for 8 registers
    logic [31:0] saved_sp;          // SP saved at exception entry
    logic [31:0] exc_return_lr;     // EXC_RETURN loaded into LR

    // --- Exception unstacking ---
    logic [2:0]  unstack_count;

    // --- Multi-register transfer (PUSH/POP/LDM/STM) ---
    logic [7:0]  multi_reg_list;
    logic [3:0]  multi_count;
    logic [31:0] multi_addr;
    logic        multi_is_push;     // 1=PUSH/STM, 0=POP/LDM
    logic        multi_is_pop_pc;   // POP includes PC
    logic        multi_is_push_lr;  // PUSH includes LR

    // --- SysTick ---
    logic [31:0] syst_csr;
    logic [23:0] syst_rvr;
    logic [23:0] syst_cvr;
    logic        syst_countflag;    // Set when counter hits 0, clear on read

    // --- Debug ---
    logic        dbg_halted_reg;
    logic        dbg_ack_reg;
    logic        dbg_single_step;

    // --- ALU result write ---
    logic [31:0] exec_result;      // Final result to write to register
    logic        exec_write_en;    // Write enable for this instruction
    logic [3:0]  exec_write_sel;   // Which register to write
    logic        exec_flag_en;     // Update APSR flags

    // --- Branch target ---
    logic [31:0] branch_target;
    logic        branch_taken;

    // ==================================================================
    // 6. Reset Synchronizer
    //    Async assert, sync deassert
    // ==================================================================
    always_ff @(posedge HCLK or negedge HRESETn) begin
        if (!HRESETn) begin
            rst_sync_n <= 1'b0;
        end else begin
            rst_sync_n <= 1'b1;
        end
    end

    // ==================================================================
    // 7. Input Synchronizers (2-stage FF)
    // ==================================================================

    // --- IRQ synchronizer (per-bit, level-sensitive) ---
    generate
        genvar i;
        for (i = 0; i < IRQ_NUM; i = i + 1) begin : gen_irq_sync
            always_ff @(posedge HCLK or negedge HRESETn) begin
                if (!HRESETn) begin
                    irq_sync1[i] <= 1'b0;
                    irq_sync2[i] <= 1'b0;
                end else begin
                    irq_sync1[i] <= IRQ[i];
                    irq_sync2[i] <= irq_sync1[i];
                end
            end
        end
    endgenerate

    // --- NMI synchronizer (edge-sensitive, rising edge detect) ---
    always_ff @(posedge HCLK or negedge HRESETn) begin
        if (!HRESETn) begin
            nmi_sync1   <= 1'b0;
            nmi_sync2   <= 1'b0;
            nmi_delayed <= 1'b0;
        end else begin
            nmi_sync1   <= NMI;
            nmi_sync2   <= nmi_sync1;
            nmi_delayed <= nmi_sync2;
        end
    end
    assign nmi_edge = nmi_sync2 & ~nmi_delayed;

    // --- DBGRQ synchronizer (level-sensitive) ---
    always_ff @(posedge HCLK or negedge HRESETn) begin
        if (!HRESETn) begin
            dbgrq_sync1 <= 1'b0;
            dbgrq_sync2 <= 1'b0;
        end else begin
            dbgrq_sync1 <= DBGRQ;
            dbgrq_sync2 <= dbgrq_sync1;
        end
    end

    // ==================================================================
    // 8. Handler Mode Detection
    // ==================================================================
    assign handler_mode = (ipsr_reg[8:0] != 9'd0);
    assign control_spsel = control_spsel_reg;

    // ==================================================================
    // 9. Register File — Read Ports (combinational)
    // ==================================================================
    // Active SP selection
    assign active_sp = handler_mode ? msp_reg :
                       (control_spsel ? psp_reg : msp_reg);

    always_comb begin
        // Read port 1
        case (reg_r1_sel)
            4'd0,4'd1,4'd2,4'd3,4'd4,4'd5,4'd6,4'd7,
            4'd8,4'd9,4'd10,4'd11,4'd12:
                reg_r1_data = gprf[reg_r1_sel[3:0]];
            4'd13: reg_r1_data = active_sp;
            4'd14: reg_r1_data = lr_reg;
            4'd15: reg_r1_data = pc_reg;
            default: reg_r1_data = 32'd0;
        endcase

        // Read port 2
        case (reg_r2_sel)
            4'd0,4'd1,4'd2,4'd3,4'd4,4'd5,4'd6,4'd7,
            4'd8,4'd9,4'd10,4'd11,4'd12:
                reg_r2_data = gprf[reg_r2_sel[3:0]];
            4'd13: reg_r2_data = active_sp;
            4'd14: reg_r2_data = lr_reg;
            4'd15: reg_r2_data = pc_reg;
            default: reg_r2_data = 32'd0;
        endcase
    end

    // ==================================================================
    // 10. Special Register Composition
    // ==================================================================
    assign apsr_reg = {apsr_n, apsr_z, apsr_c, apsr_v, 28'd0};
    assign epsr_reg = 32'h0100_0000; // T-bit always 1

    // ==================================================================
    // 11. Instruction Decoder (combinational)
    // ==================================================================
    assign instr_hw = instr_reg[15:0];
    assign instr_is_32bit = (instr_reg[31:27] == 5'b11110);

    always_comb begin
        // --- Default decoder outputs ---
        dec_class      = CLS_SYSTEM;
        dec_alu_op     = ALU_NOP;
        dec_rd         = 4'd0;
        dec_rn         = 4'd0;
        dec_rm         = 4'd0;
        dec_imm        = 32'd0;
        dec_shift_amt  = 5'd0;
        dec_mem_size   = 2'b10; // WORD
        dec_mem_signext = 1'b0;
        dec_write_en   = 1'b0;
        dec_flag_en    = 1'b0;
        dec_branch_en  = 1'b0;
        dec_branch_cond = 4'hE; // AL (always)
        dec_is_32bit   = 1'b0;
        dec_reg_list   = 8'd0;
        dec_push_lr    = 1'b0;
        dec_pop_pc     = 1'b0;

        if (instr_is_32bit) begin
            // ==========================================================
            // Thumb-2 (32-bit) Instruction Decode
            // ==========================================================
            dec_is_32bit = 1'b1;

            if (instr_reg[31:27] == 5'b11110 && instr_reg[15] == 1'b1 && instr_reg[14] == 1'b1 && instr_reg[12] == 1'b1) begin
                // BL: 11110 S imm10 | 11 J1 1 imm11 J2
                dec_class    = CLS_BL;
                dec_write_en = 1'b1;
                dec_rd       = 4'd14; // LR

                // Build branch offset
                // S = instr_reg[26]
                // imm10 = instr_reg[25:16]
                // J1 = instr_reg[13]
                // J2 = instr_reg[11]
                // imm11 = instr_reg[10:0]
                // I1 = !(J1 XOR S), I2 = !(J2 XOR S)
                logic s_bit, i1_bit, i2_bit;
                s_bit = instr_reg[26];
                i1_bit = ~(instr_reg[13] ^ s_bit);
                i2_bit = ~(instr_reg[11] ^ s_bit);
                dec_imm = {s_bit ? 7'h7F : 7'h00, s_bit, i1_bit, i2_bit,
                           instr_reg[25:16], instr_reg[10:0], 1'b0};
            end
            else if (instr_reg[31:20] == 12'b11110_0100_11) begin
                // MRS: 11110 0100 11 | (0_0_0_0_sysm_0000_Rd)
                dec_class    = CLS_SYSTEM;
                dec_write_en = 1'b1;
                dec_rd       = {1'b0, instr_reg[3:0]};
                dec_rn       = {1'b0, instr_reg[11:8]}; // SYSM
                dec_imm      = 32'd0; // MRS direction indicator
            end
            else if (instr_reg[31:20] == 12'b11110_0100_10) begin
                // MSR: 11110 0100 10 | (0_0_0_0_sysm_0000_Rn)
                dec_class    = CLS_SYSTEM;
                dec_rn       = {1'b0, instr_reg[3:0]}; // Source register
                dec_rm       = {1'b0, instr_reg[11:8]}; // SYSM
                dec_imm      = 32'd1; // MSR direction indicator
            end
            else begin
                // DMB, DSB, ISB, and other barriers — treat as NOP
                dec_class    = CLS_SYSTEM;
                dec_alu_op   = ALU_NOP;
            end
        end else begin
            // ==========================================================
            // Thumb-16 Instruction Decode
            // ==========================================================
            case (instr_hw[15:10])
                // ------ Shift by immediate ------
                6'b000000: begin // LSL (immediate)
                    dec_class     = CLS_SHIFT;
                    dec_alu_op    = ALU_LSL;
                    dec_shift_amt = instr_hw[10:6];
                    dec_rm        = {1'b0, instr_hw[5:3]};
                    dec_rd        = {1'b0, instr_hw[2:0]};
                    dec_write_en  = 1'b1;
                    dec_flag_en   = 1'b1;
                end
                6'b000001: begin // LSR (immediate)
                    dec_class     = CLS_SHIFT;
                    dec_alu_op    = ALU_LSR;
                    dec_shift_amt = (instr_hw[10:6] == 5'd0) ? 5'd32 : instr_hw[10:6];
                    dec_rm        = {1'b0, instr_hw[5:3]};
                    dec_rd        = {1'b0, instr_hw[2:0]};
                    dec_write_en  = 1'b1;
                    dec_flag_en   = 1'b1;
                end
                6'b000010: begin // ASR (immediate)
                    dec_class     = CLS_SHIFT;
                    dec_alu_op    = ALU_ASR;
                    dec_shift_amt = (instr_hw[10:6] == 5'd0) ? 5'd32 : instr_hw[10:6];
                    dec_rm        = {1'b0, instr_hw[5:3]};
                    dec_rd        = {1'b0, instr_hw[2:0]};
                    dec_write_en  = 1'b1;
                    dec_flag_en   = 1'b1;
                end

                // ------ ADD/SUB register ------
                6'b000011: begin
                    dec_rn = {1'b0, instr_hw[8:6]};
                    dec_rm = {1'b0, instr_hw[5:3]};
                    dec_rd = {1'b0, instr_hw[2:0]};
                    dec_flag_en = 1'b1;
                    if (instr_hw[9] == 1'b0) begin
                        dec_class  = CLS_ALU;
                        dec_alu_op = ALU_ADD;
                    end else begin
                        dec_class  = CLS_ALU;
                        dec_alu_op = ALU_SUB;
                    end
                    dec_write_en = 1'b1;
                end

                // ------ ADD/SUB 3-bit immediate ------
                6'b000100: begin
                    dec_rn   = {1'b0, instr_hw[8:6]};
                    dec_imm  = {29'd0, instr_hw[5:3]};
                    dec_rd   = {1'b0, instr_hw[2:0]};
                    dec_flag_en = 1'b1;
                    if (instr_hw[9] == 1'b0) begin
                        dec_class  = CLS_ALU;
                        dec_alu_op = ALU_ADD;
                    end else begin
                        dec_class  = CLS_ALU;
                        dec_alu_op = ALU_SUB;
                    end
                    dec_write_en = 1'b1;
                end

                // ------ MOV/CMP 8-bit immediate ------
                6'b000101: begin
                    dec_rd = {1'b0, instr_hw[10:8]};
                    dec_imm = {24'd0, instr_hw
